<script setup>
import { computed, ref, watch } from 'vue'
import { useI18n } from 'vue-i18n'
import { activeServer } from '../stores/serverStore.js'
import { usePageMeta } from '../composables/usePageMeta.js'

const { t, locale } = useI18n()

// Prefer a Russian description when the UI is in Russian, falling back to the
// mod's original (English) metadata description.
function descOf(m) {
  if (locale.value === 'ru' && m.description_ru) return m.description_ru
  return m.description || ''
}

// Per-server mod list generated by scripts/generate_mods_list.py into
// public/mods/<slug>.json. Loaded lazily; a 404 just means no list for this server.
const mods = ref([])
const loaded = ref(false)
const query = ref('')

async function loadMods(slug) {
  mods.value = []
  loaded.value = false
  if (!slug) return
  try {
    const res = await fetch(`/mods/${encodeURIComponent(slug)}.json`)
    if (res.ok) {
      const data = await res.json()
      mods.value = Array.isArray(data) ? data : []
    }
  } catch {
    mods.value = []
  } finally {
    loaded.value = true
  }
}

const serverName = computed(() => activeServer.value?.name || '')

const filtered = computed(() => {
  const q = query.value.trim().toLowerCase()
  if (!q) return mods.value
  return mods.value.filter(
    (m) =>
      m.name?.toLowerCase().includes(q) ||
      m.id?.toLowerCase().includes(q) ||
      m.description?.toLowerCase().includes(q) ||
      m.description_ru?.toLowerCase().includes(q),
  )
})

watch(
  () => activeServer.value?.slug,
  (slug) => {
    query.value = ''
    loadMods(slug)
  },
  { immediate: true },
)

usePageMeta({
  title: t('serverGuide.modsTitle'),
  description: t('serverGuide.modsSubtitle'),
  url: 'https://void-rp.ru/mods',
  breadcrumbs: [
    { name: t('nav.home'), url: '/' },
    { name: t('serverGuide.modsTitle') },
  ],
})
</script>

<template>
  <section class="gp py-3 md:py-4">
    <div class="container-shell max-w-[1240px] space-y-3">

      <!-- Header -->
      <header class="gp-header">
        <div class="gp-header__left">
          <p class="gp-eyebrow">{{ t('serverGuide.tabMods') }}<span v-if="serverName"> · {{ serverName }}</span></p>
          <h1 class="gp-h1">{{ t('serverGuide.modsTitle') }}</h1>
          <p class="gp-desc">{{ t('serverGuide.modsSubtitle') }}</p>
        </div>
      </header>

      <!-- Empty (no list for this server) -->
      <div v-if="loaded && mods.length === 0" class="surface-card sg-empty">
        <div class="sg-empty__icon">🧩</div>
        <h2 class="sg-empty__title">{{ t('serverGuide.emptyTitle') }}</h2>
        <p class="sg-empty__text">{{ t('serverGuide.emptyText') }}</p>
      </div>

      <template v-else>
        <div class="sg-mods__bar surface-card">
          <input
            v-model="query"
            type="search"
            class="sg-mods__search"
            :placeholder="t('serverGuide.modsSearch')"
          />
          <span class="sg-mods__count">{{ t('serverGuide.modsCount', { shown: filtered.length, total: mods.length }) }}</span>
        </div>

        <div v-if="filtered.length === 0" class="surface-card sg-mods__empty">
          {{ t('serverGuide.modsEmpty') }}
        </div>

        <div v-else class="sg-mods__grid">
          <article v-for="m in filtered" :key="m.id" class="surface-card sg-mod">
            <div class="sg-mod__head">
              <h3 class="sg-mod__name">{{ m.name }}</h3>
              <span v-if="m.version" class="sg-mod__ver">{{ m.version }}</span>
            </div>
            <p class="sg-mod__desc" :class="{ 'sg-mod__desc--muted': !descOf(m) }">
              {{ descOf(m) || t('serverGuide.modsNoDesc') }}
            </p>
            <code class="sg-mod__id">{{ m.id }}</code>
          </article>
        </div>
      </template>

    </div>
  </section>
</template>

