  flex: 1; min-width: 180px; padding: .5rem .75rem; border-radius: 9px;
  background: rgba(0,0,0,.28); border: 1px solid rgba(255,255,255,.1);
  color: #f0f4ff; font-size: .85rem;
}
.sg-mods__search:focus { outline: none; border-color: rgba(134,239,172,.45); }
.sg-mods__count { font-size: .76rem; color: rgb(100 116 139); white-space: nowrap; }
.sg-mods__empty { text-align: center; padding: 2.5rem 1rem; color: rgb(100 116 139); font-size: .85rem; }
.sg-mods__grid {
  display: grid; gap: .55rem;
  grid-template-columns: repeat(auto-fill, minmax(260px, 1fr));
}
.sg-mod { padding: .75rem .85rem; display: flex; flex-direction: column; gap: .3rem; }
.sg-mod__head { display: flex; align-items: baseline; justify-content: space-between; gap: .5rem; }
.sg-mod__name { font-size: .88rem; font-weight: 800; color: #f0f4ff; margin: 0; line-height: 1.25; }
.sg-mod__ver {
  flex-shrink: 0; font-size: .66rem; font-weight: 700; color: rgb(100 116 139);
  font-variant-numeric: tabular-nums; font-family: ui-monospace, monospace;
}
.sg-mod__desc { font-size: .78rem; line-height: 1.5; color: rgb(148 163 184); margin: 0; }
.sg-mod__desc--muted { color: rgb(100 116 139); font-style: italic; }
